package com.example.myapp.deeplink

import android.app.Activity
import android.content.Context
import android.content.Intent
import android.net.Uri
import com.example.myapp.ui.payment.PaymentConfirmActivity
import com.example.myapp.ui.profile.ProfileActivity
import com.example.myapp.ui.home.HomeActivity

object DeepLinkHandler {
    private const val SCHEME = "myapp"
    private const val HOST_PROFILE = "profile"
    private const val HOST_PAYMENT = "payment"
    private const val PATH_CONFIRM = "confirm"

    fun handle(context: Context, uriString: String?): Boolean {
        if (uriString.isNullOrBlank()) return false
        return runCatching { Uri.parse(uriString) }
            .getOrNull()
            ?.let { handle(context, it) }
            ?: false
    }

    fun handle(context: Context, uri: Uri?): Boolean {
        if (uri == null) return false
        if (!uri.scheme.equals(SCHEME, ignoreCase = true)) return false

        val intent = when (uri.host?.lowercase()) {
            HOST_PROFILE -> buildProfileIntent(context, uri)
            HOST_PAYMENT -> buildPaymentIntent(context, uri)
            else -> buildFallbackIntent(context, uri)
        } ?: return false

        if (context !is Activity) {
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        }

        context.startActivity(intent)
        return true
    }

    private fun buildProfileIntent(context: Context, uri: Uri): Intent? {
        val userId = uri.pathSegments.firstOrNull()?.takeIf { it.isNotBlank() } ?: return null
        return Intent(context, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_USER_ID, userId)
            putExtra(EXTRA_DEEP_LINK_URI, uri.toString())
        }
    }

    private fun buildPaymentIntent(context: Context, uri: Uri): Intent? {
        val firstSegment = uri.pathSegments.firstOrNull()?.lowercase()
        return if (firstSegment == PATH_CONFIRM) {
            Intent(context, PaymentConfirmActivity::class.java).apply {
                putExtra(EXTRA_DEEP_LINK_URI, uri.toString())
            }
        } else {
            null
        }
    }

    private fun buildFallbackIntent(context: Context, uri: Uri): Intent {
        return Intent(context, HomeActivity::class.java).apply {
            putExtra(EXTRA_DEEP_LINK_URI, uri.toString())
        }
    }

    const val EXTRA_DEEP_LINK_URI = "extra_deep_link_uri"
}